1017	+export function useBrainState() {
1018	+  const [brainState, setBrainState] = useState<BrainState>(IDLE)
1019	+  const [activeStage, setActiveStage] = useState<string>('idle')
1020	+  const esRef = useRef<EventSource | null>(null)
1021	+
1022	+  const activate = useCallback(() => {
1023	+    if (esRef.current) {
1024	+      esRef.current.close()
1025	+    }
1026	+
1027	+    const es = new EventSource('/api/brain-state')
1028	+    esRef.current = es
1029	+
1030	+    es.onmessage = (e) => {
1031	+      try {
1032	+        const { stage, state } = JSON.parse(e.data)
1033	+        setActiveStage(stage)
1034	+        setBrainState(state)
1035	+      } catch {
1036	+        // ignore parse errors
1037	+      }
1038	+    }
1039	+
1040	+    es.onerror = () => {
1041	+      es.close()
1042	+      esRef.current = null
1043	+      // Fade back to idle
1044	+      setTimeout(() => {
1045	+        setBrainState(IDLE)
1046	+        setActiveStage('idle')
1047	+      }, 800)
1048	+    }
1049	+  }, [])
1050	+
1051	+  return { brainState, activeStage, activate }
