1059	+import { useState, useCallback } from 'react';
1060	+
1061	+export function useStreamingChat() {
1062	+    const [messages, setMessages] = useState<{ role: string; content: string }[]>([]);
1063	+    const [isStreaming, setIsStreaming] = useState(false);
1064	+
1065	+    const sendMessage = useCallback(async (prompt: string, history: any[]) => {
1066	+        setIsStreaming(true);
1067	+        setMessages((prev) => [...prev, { role: 'user', content: prompt }]);
1068	+        
1069	+        let fullResponse = '';
1070	+        setMessages((prev) => [...prev, { role: 'assistant', content: '' }]);
1071	+
1072	+        const response = await fetch('/api/chat/stream', {
1073	+            method: 'POST',
1074	+            body: JSON.stringify({ prompt, history }),
1075	+        });
1076	+
1077	+        const reader = response.body?.getReader();
1078	+        const decoder = new TextDecoder();
1079	+
1080	+        if (!reader) return;
1081	+
1082	+        try {
1083	+            while (true) {
1084	+                const { done, value } = await reader.read();
1085	+                if (done) break;
1086	+
1087	+                const chunk = decoder.decode(value, { stream: true });
1088	+                const json = JSON.parse(chunk);
1089	+
1090	+                if (json.chunk) {
1091	+                    fullResponse += json.chunk;
1092	+                    setMessages((prev) => {
1093	+                        const next = [...prev];
1094	+                        next[next.length - 1].content = fullResponse;
1095	+                        return next;
1096	+                    });
1097	+                }
1098	+            }
1099	+        } catch (e) {
1100	+            console.error('Streaming error', e);
1101	+        } finally {
1102	+            setIsStreaming(false);
1103	+        }
1104	+    }, []);
1105	+
1106	+    return { messages, isStreaming, sendMessage };
1107	+}
